function findMatchingBracket(source: string, openIndex: number): number {
	let depth = 0;
	let quote: '"' | "'" | "`" | undefined;
	let escaped = false;
	let lineComment = false;
	let blockComment = false;

	for (let index = openIndex; index < source.length; index += 1) {
		const current = source[index];
		const next = source[index + 1];

		if (lineComment) {
			if (current === "\n") {
				lineComment = false;
			}
			continue;
		}

		if (blockComment) {
			if (current === "*" && next === "/") {
				blockComment = false;
				index += 1;
			}
			continue;
		}

		if (quote) {
			if (escaped) {
				escaped = false;
			} else if (current === "\\") {
				escaped = true;
			} else if (current === quote) {
				quote = undefined;
			}
			continue;
		}

		if (current === "/" && next === "/") {
			lineComment = true;
			index += 1;
			continue;
		}

		if (current === "/" && next === "*") {
			blockComment = true;
			index += 1;
			continue;
		}

		if (current === '"' || current === "'" || current === "`") {
			quote = current;
			continue;
		}

		if (current === "[") {
			depth += 1;
		} else if (current === "]") {
			depth -= 1;
			if (depth === 0) {
				return index;
			}
		}
	}

	return -1;
}

