export async function runCli(
	argv = process.argv,
	cwd = process.cwd(),
	ui?: CliUi,
): Promise<void> {
	const command = argv[2];
	if (command === "install") {
		const installUi = ui ?? createConsoleUi();
		try {
			const options = parseInstallOptions(argv.slice(3));
			await install(cwd, { options, ui: installUi });
			return;
		} catch (error) {
			const message =
